mapper.select:
select *
from batch.workflow_run
where tenant_id = #{tenantId}
  and id = #{id}

select *
from batch.workflow_run
where tenant_id = #{tenantId}
  and related_job_instance_id = #{relatedJobInstanceId}
order by id desc
limit 1

select *
from batch.workflow_run
where tenant_id = #{tenantId}

    and workflow_definition_id = #{workflowDefinitionId}


    and run_status = #{runStatus}

order by id desc
